import { useEffect, useRef, useState, useCallback } from "react";
import { motion } from "framer-motion";
import { ChevronLeft, ChevronRight } from "lucide-react";

const BRANDS = [
  { name: "3M", img: "data:image/svg+xml;base64," },
  { name: "ABB", img: "data:image/svg+xml;base64," },
  { name: "Bosch", img: "data:image/svg+xml;base64," },
  { name: "Caterpillar", img: "data:image/svg+xml;base64," },
  { name: "Cisco", img: "data:image/svg+xml;base64," },
  { name: "Dell", img: "data:image/svg+xml;base64," },
  { name: "Epson", img: "data:image/svg+xml;base64," },
  { name: "Honda", img: "data:image/svg+xml;base64," },
  { name: "HP", img: "data:image/svg+xml;base64," },
  { name: "Intel", img: "data:image/svg+xml;base64," },
  { name: "LG", img: "data:image/svg+xml;base64," },
  { name: "Mahindra", img: "data:image/svg+xml;base64," },
  { name: "Mitsubishi", img: "data:image/svg+xml;base64,PHN2ZyBmaWxsPSIjRkYwMDAwIiByb2xlPSJpbWciIHZpZXdCb3g9IjAgMCAyNCAyNCIgeG1sbnM9Imh0dHA6Ly93d3cudzMub3JnLzIwMDAvc3ZnIj48dGl0bGU+TWl0c3ViaXNoaTwvdGl0bGU+PHBhdGggZD0iTTggMjIuMzhIMGw0LTYuOTJoOHptOCAwaDhsLTQtNi45MmgtOHptMC0xMy44NGwtNC02LjkyLTQgNi45MiA0IDYuOTJaIi8+PC9zdmc+" },
  { name: "Panasonic", img: "data:image/svg+xml;base64," },
  { name: "Rockwell", img: "data:image/svg+xml;base64," },
  { name: "Samsung", img: "data:image/svg+xml;base64," },
  { name: "Schneider Electric", img: "data:image/svg+xml;base64," },
  { name: "Siemens", img: "data:image/svg+xml;base64," },
  { name: "Sony", img: "data:image/svg+xml;base64," },
  { name: "Tata", img: "data:image/svg+xml;base64," },
  { name: "Toyota", img: "data:image/svg+xml;base64," },
  { name: "Unilever", img: "data:image/svg+xml;base64," }
];

const stats = [
  { value: "12+", label: "Industry Sectors" },
  { value: "25+", label: "States Covered" },
  { value: "10,000+", label: "Machines Installed" },
];

const GAP = 18;
const INTERVAL_MS = 2500;

const Clients = () => {
  const trackRef = useRef<HTMLDivElement>(null);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const isAnimatingRef = useRef(false);
  const indexRef = useRef(0);
  const touchStartRef = useRef(0);

  const [activePage, setActivePage] = useState(0);
  const [visible, setVisible] = useState(() =>
    typeof window !== "undefined" && window.innerWidth < 640 ? 3 : 5
  );

  useEffect(() => {
    const onResize = () => setVisible(window.innerWidth < 640 ? 3 : 5);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  const totalPages = Math.ceil(BRANDS.length / visible);

  const containerRef = useRef<HTMLDivElement>(null);

  const cardWidth = useCallback(() => {
    const container = containerRef.current;
    if (!container) return 160;
    const w = container.offsetWidth;
    const raw = Math.floor((w - GAP * (visible - 1)) / visible);
    return Math.max(80, raw);
  }, [visible]);

  const setPos = useCallback((idx: number, animate: boolean) => {
    const track = trackRef.current;
    if (!track) return;
    const cw = cardWidth();
    track.style.transition = animate ? "transform 700ms cubic-bezier(0.4,0,0.2,1)" : "none";
    track.style.transform = `translateX(-${(visible + idx) * (cw + GAP)}px)`;
  }, [cardWidth, visible]);

  useEffect(() => {
    const onResize = () => setPos(indexRef.current, false);
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, [setPos]);

  const advance = useCallback((dir: number) => {
    if (isAnimatingRef.current) return;
    isAnimatingRef.current = true;
    indexRef.current += dir;
    setPos(indexRef.current, true);
  }, [setPos]);

  const startAuto = useCallback(() => {
    if (timerRef.current) clearInterval(timerRef.current);
    timerRef.current = setInterval(() => advance(visible), INTERVAL_MS);
  }, [advance, visible]);

  const stopAuto = useCallback(() => {
    if (timerRef.current) clearInterval(timerRef.current);
  }, []);

  useEffect(() => {
    indexRef.current = 0;
    setActivePage(0);
    // Small delay so containerRef dimensions are ready
    const t = setTimeout(() => setPos(0, false), 10);
    startAuto();
    return () => { clearTimeout(t); stopAuto(); };
  }, [visible, setPos, startAuto, stopAuto]);

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;
    const onEnd = () => {
      isAnimatingRef.current = false;
      if (indexRef.current >= BRANDS.length) indexRef.current -= BRANDS.length;
      if (indexRef.current < 0) indexRef.current += BRANDS.length;
      setPos(indexRef.current, false);
      setActivePage(Math.round(indexRef.current / visible) % Math.ceil(BRANDS.length / visible));
    };
    track.addEventListener("transitionend", onEnd);
    return () => track.removeEventListener("transitionend", onEnd);
  }, [setPos, visible]);

  const goTo = (page: number) => {
    if (isAnimatingRef.current) return;
    isAnimatingRef.current = true;
    indexRef.current = page * visible;
    setPos(indexRef.current, true);
    setActivePage(page);
    startAuto();
  };

  const allCards = [...BRANDS.slice(-visible), ...BRANDS, ...BRANDS.slice(0, visible)];

  return (
    <section id="clients" className="py-12 bg-white relative overflow-hidden">
      {/* Hex bg pattern */}
      <div className="absolute inset-0 pointer-events-none opacity-[0.025]" aria-hidden="true">
        <svg width="100%" height="100%">
          <defs>
            <pattern id="hexPat" x="0" y="0" width="60" height="52" patternUnits="userSpaceOnUse">
              <polygon points="30,2 56,16 56,44 30,58 4,44 4,16" fill="none" stroke="hsl(var(--navy))" strokeWidth="1" />
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#hexPat)" />
        </svg>
      </div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
          transition={{ duration: 0.7 }}
          className="text-center mb-6"
        >
          <div className="inline-flex items-center gap-2 mb-3">
            <span className="block w-6 h-px bg-orange" />
            <span className="text-orange text-sm font-display font-semibold tracking-widest uppercase">
              Our Clients
            </span>
            <span className="block w-6 h-px bg-orange" />
          </div>

          <div className="w-12 h-0.5 bg-gradient-to-r from-orange to-orange/40 rounded-full mx-auto mb-4" />

          <h2 className="text-2xl sm:text-3xl lg:text-4xl font-bold font-display text-foreground">
            Trusted by{" "}
            <span className="relative inline-block">
              Leading Brands
            </span>
          </h2>
          <p className="mt-3 text-muted-foreground text-sm">Serving 500+ Manufacturers Across India</p>

        </motion.div>

        {/* Carousel */}
        <div
          className="relative"
          onMouseEnter={stopAuto}
          onMouseLeave={startAuto}
          onTouchStart={(e) => { touchStartRef.current = e.touches[0].clientX; }}
          onTouchEnd={(e) => {
            const dx = e.changedTouches[0].clientX - touchStartRef.current;
            if (Math.abs(dx) > 40) { advance(dx < 0 ? visible : -visible); startAuto(); }
          }}
        >
          <div className="absolute left-0 top-0 bottom-0 w-4 bg-gradient-to-r from-white to-transparent z-10 pointer-events-none" />
          <div className="absolute right-0 top-0 bottom-0 w-4 bg-gradient-to-l from-white to-transparent z-10 pointer-events-none" />

          <div ref={containerRef} className="overflow-hidden py-2">
            <div ref={trackRef} className="flex items-center" style={{ gap: GAP }}>
              {allCards.map((brand, i) => (
                <div
                  key={`${brand.name}-${i}`}
                  className="flex-shrink-0 h-20 bg-white border border-border rounded-xl flex items-center justify-center px-3 py-2.5 shadow-sm hover:-translate-y-1 hover:shadow-md hover:border-orange/20 transition-all duration-300 cursor-default"
                  style={{ width: cardWidth() }}
                  title={brand.name}
                >
                  <img
                    src={brand.img}
                    alt={brand.name}
                    className="max-h-12 max-w-full w-auto h-auto object-contain block"
                  />
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Nav */}
        <div className="flex items-center justify-center gap-4 mt-6">
          <div className="flex items-center gap-2">
            {Array.from({ length: totalPages }).map((_, i) => (
              <button
                key={i}
                onClick={() => goTo(i)}
                aria-label={`Go to page ${i + 1}`}
                className={`h-2 rounded-full transition-all duration-300 ${i === activePage ? "w-6 bg-orange" : "w-2 bg-border hover:bg-muted-foreground"}`}
              />
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Clients;